/**
 * 轻量级二维码扫描库
 * 基于 jsQR 的简化版本，用于从图片中解析二维码
 * 
 * 使用方法：
 * const result = await QRScanner.scanImage(imageElement);
 * if (result) {
 *     console.log('QR Code:', result.data);
 * }
 */
var QRScanner = (function () {
    'use strict';

    /**
     * 从图片元素中扫描二维码
     * @param {HTMLImageElement|HTMLCanvasElement} image 图片元素
     * @returns {Object|null} 扫描结果 {data: string} 或 null
     */
    function scanImage(image) {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        // 设置canvas尺寸
        canvas.width = image.width || image.naturalWidth;
        canvas.height = image.height || image.naturalHeight;

        // 绘制图片到canvas
        ctx.drawImage(image, 0, 0, canvas.width, canvas.height);

        // 获取图片数据
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

        // 使用第三方库解析二维码
        // 这里集成 jsQR 库的核心功能
        try {
            const code = jsQR(imageData.data, imageData.width, imageData.height, {
                inversionAttempts: "dontInvert",
            });

            return code;
        } catch (error) {
            console.error('QR scan error:', error);
            return null;
        }
    }

    /**
     * 从文件对象中扫描二维码
     * @param {File} file 图片文件
     * @returns {Promise<Object|null>} 扫描结果
     */
    function scanFile(file) {
        return new Promise((resolve, reject) => {
            if (!file.type.startsWith('image/')) {
                reject(new Error('请选择图片文件'));
                return;
            }

            const reader = new FileReader();
            reader.onload = function (e) {
                const img = new Image();
                img.onload = function () {
                    const result = scanImage(img);
                    resolve(result);
                };
                img.onerror = function () {
                    reject(new Error('图片加载失败'));
                };
                img.src = e.target.result;
            };
            reader.onerror = function () {
                reject(new Error('文件读取失败'));
            };
            reader.readAsDataURL(file);
        });
    }

    return {
        scanImage: scanImage,
        scanFile: scanFile
    };
})();

